{
    "title": "人工智能发展简史",
    "chapters": [
        {
            "title": "引言：AI的起源与定义",
            "pages": [
                {
                    "title": "什么是人工智能？",
                    "bullets": [
                        "人工智能（AI）是研究、开发用于模拟、延伸和扩展人的智能的理论、方法、技术及应用系统的一门技术科学。",
                        "核心目标是让机器能够像人一样思考、学习、决策和解决问题。",
                        "发展历程充满波折，经历了多次繁荣与寒冬。"
                    ],
                    "notes": "开场提问：你认为什么是智能？机器能拥有智能吗？引出图灵测试的概念。"
                },
                {
                    "title": "萌芽与诞生（1950s-1960s）",
                    "bullets": [
                        "1950年：艾伦·图灵发表《计算机器与智能》，提出“图灵测试”。",
                        "1956年：达特茅斯会议，约翰·麦卡锡等人正式提出“人工智能”术语，AI学科诞生。",
                        "早期成果：逻辑理论家程序、通用问题求解器、感知机（最早的神经网络模型）。",
                        "局限性：计算能力不足，算法简单，导致60年代末陷入第一次寒冬。"
                    ],
                    "notes": "强调达特茅斯会议的历史性意义，类比为AI的“出生证明”。可简要解释图灵测试的原理。"
                }
            ]
        },
        {
            "title": "探索、挫折与复兴",
            "pages": [
                {
                    "title": "第一次繁荣与寒冬（1970s）",
                    "bullets": [
                        "早期进展：专家系统雏形出现，如MYCIN（医疗诊断）、DENDRAL（化学分析）。",
                        "重大挫折：1973年《莱特希尔报告》严厉批评AI研究未达预期。",
                        "后果：英美政府大幅削减资金，AI研究进入第一个“寒冬”。",
                        "反思：对“通用智能”的过度乐观遭遇现实打击。"
                    ],
                    "notes": "讲解专家系统的工作原理：基于规则的知识库。过渡：寒冬之后，AI如何找到新的出路？"
                },
                {
                    "title": "专家系统时代（1980s）",
                    "bullets": [
                        "复兴标志：专家系统商业化成功，如XCON（计算机配置）每年为DEC节省数千万美元。",
                        "国家战略：日本“第五代计算机”项目，美国MCC项目，推动知识工程。",
                        "局限性：系统脆弱、维护成本高、知识难以迁移（窄AI）。",
                        "再次遇冷：日本项目未达目标，80年代末资金再次削减。"
                    ],
                    "notes": "举例说明专家系统的成功与局限。提问：如果知识需要不断更新，纯规则系统是否可持续？"
                },
                {
                    "title": "机器学习崛起（1990s）",
                    "bullets": [
                        "范式转变：从基于规则的“符号主义”转向数据驱动的“机器学习”。",
                        "算法突破：支持向量机（SVM）、随机森林等统计学习方法成为主流。",
                        "里程碑事件：1997年，IBM“深蓝”击败国际象棋世界冠军卡斯帕罗夫。",
                        "意义：证明了在规则明确的复杂领域，机器可以超越人类。"
                    ],
                    "notes": "对比符号主义与机器学习（连接主义）的差异。强调数据的重要性开始凸显。"
                }
            ]
        },
        {
            "title": "深度学习的革命与大模型时代",
            "pages": [
                {
                    "title": "深度学习爆发（2010s）",
                    "bullets": [
                        "三大驱动力：大数据、强大算力（GPU）、算法创新（如ReLU、Dropout）。",
                        "关键里程碑：2012年AlexNet在ImageNet竞赛中大幅领先，引爆深度学习热潮。",
                        "历史性胜利：2016年AlphaGo击败围棋冠军李世石，攻克“人类智慧高地”。",
                        "NLP突破：Transformer架构（2017）出现，为后续大模型奠定基础。"
                    ],
                    "notes": "展示AlexNet网络结构图或AlphaGo对弈画面。强调深度学习让AI从“特征工程”进入“表示学习”。"
                },
                {
                    "title": "大模型与生成式AI时代（2020s至今）",
                    "bullets": [
                        "现象级应用：2022年ChatGPT发布，用户增长创历史纪录，让AI全民化。",
                        "能力飞跃：GPT-4等模型展现出强大的多模态理解、推理和生成能力。",
                        "全球竞赛：中国厂商快速跟进（文心一言、通义千问、ChatGLM、DeepSeek等）。",
                        "开源趋势：2025年，开源模型性能逼近闭源，推动技术民主化。"
                    ],
                    "notes": "可现场演示一段与ChatGPT的对话。讨论：大模型为何能“涌现”出小模型没有的能力？"
                },
                {
                    "title": "AI能力演进路径",
                    "bullets": [
                        "感知智能：让机器能看（CV）、能听（ASR）、能读（NLP）。",
                        "认知智能：让机器能理解、推理、规划。",
                        "生成智能：让机器能创作文本、图像、代码、视频。",
                        "决策智能与AGI探索：迈向更自主、更通用的智能体（Agent）。"
                    ],
                    "notes": "用图表展示从感知、认知到生成、决策的演进过程。过渡到当前面临的挑战。"
                }
            ]
        },
        {
            "title": "当前挑战、伦理与未来展望",
            "pages": [
                {
                    "title": "面临的核心挑战",
                    "bullets": [
                        "技术挑战：“幻觉”问题、能耗巨大（算力与碳排放）、可解释性差。",
                        "数据与版权：训练数据来源的合法性与版权争议。",
                        "安全与对齐：如何确保AI的目标和行为与人类价值观一致（对齐问题）。",
                        "社会影响：就业冲击、隐私泄露、偏见与歧视、AGI的长期风险。"
                    ],
                    "notes": "举例说明“幻觉”的危害。引导学生思考：技术发展是否应设置“减速带”或“护栏”？"
                },
                {
                    "title": "未来主要发展方向",
                    "bullets": [
                        "高效与小模型：追求更低的计算成本，便于边缘设备部署。",
                        "多模态统一：实现文本、图像、声音、视频等信息的深度融合理解与生成。",
                        "具身智能：AI与机器人结合，在物理世界中学习与交互。",
                        "AI Agent：能够自主理解、规划、执行复杂任务的智能体。",
                        "可解释AI（XAI）：提高模型决策的透明度和可信度。"
                    ],
                    "notes": "展示具身智能或AI Agent的愿景图。强调未来AI将更贴近物理世界和具体任务。"
                },
                {
                    "title": "总结与思考",
                    "bullets": [
                        "AI发展史是一部在“乐观期望”与“现实瓶颈”间不断循环突破的历史。",
                        "驱动力从“规则”到“数据”再到“算力与算法”，范式持续演进。",
                        "我们正处在由大模型驱动的生成式AI浪潮之巅，能力边界快速扩展。",
                        "在拥抱技术红利的同时，必须积极应对其带来的技术、伦理与社会挑战。",
                        "未来属于那些能有效利用AI并深刻理解其边界的人。"
                    ],
                    "notes": "回顾整个发展时间线。结束语：AI不是要取代人类，而是拓展人类能力的强大工具。提问环节。"
                }
            ]
        }
    ]
}
